sir_impl <- function(
  graph,
  beta,
  gamma,
  no_sim = 100
) {
  # Argument checks
  ensure_igraph(graph)
  beta <- as.numeric(beta)
  gamma <- as.numeric(gamma)
  no_sim <- as.numeric(no_sim)

  on.exit(.Call(R_igraph_finalizer))
  # Function call
  res <- .Call(
    R_igraph_sir,
    graph,
    beta,
    gamma,
    no_sim
  )

  class(res) <- "sir"
  res
}

# ==== evolutionary-dynamics ====

deterministic_optimal_imitation_impl <- function(
  graph,
  vid,
  optimality = c("maximum", "minimum"),
  quantities,
  strategies,
  mode = c("out", "in", "all", "total")
) {
  # Argument checks
  ensure_igraph(graph)
  vid <- as_igraph_vs(graph, vid)
  if (length(vid) != 1) {
    cli::cli_abort(
      "{.arg vid} must specify exactly one vertex",
      call = rlang::caller_env()
    )
  }
  optimality <- switch_igraph_arg(optimality, "minimum" = 0L, "maximum" = 1L)
  strategies <- as.numeric(strategies)
  mode <- switch_igraph_arg(
    mode,
    "out" = 1L,
    "in" = 2L,
    "all" = 3L,
    "total" = 3L
  )

  on.exit(.Call(R_igraph_finalizer))
  # Function call
  res <- .Call(
    R_igraph_deterministic_optimal_imitation,
    graph,
    vid - 1,
    optimality,
    quantities,
    strategies,
    mode
  )

  res
}

moran_process_impl <- function(
  graph,
  weights = NULL,
  quantities,
  strategies,
  mode = c("out", "in", "all", "total")
) {
  # Argument checks
  ensure_igraph(graph)
  if (is.null(weights) && "weight" %in% edge_attr_names(graph)) {
    weights <- E(graph)$weight
  }
  if (!is.null(weights) && !all(is.na(weights))) {
    weights <- as.numeric(weights)
  } else {
    weights <- NULL
  }
  strategies <- as.numeric(strategies)
  mode <- switch_igraph_arg(
    mode,
    "out" = 1L,
    "in" = 2L,
    "all" = 3L,
    "total" = 3L
  )

  on.exit(.Call(R_igraph_finalizer))
  # Function call
  res <- .Call(
    R_igraph_moran_process,
    graph,
    weights,
    quantities,
    strategies,
    mode
  )
  if (igraph_opt("add.vertex.names") && is_named(graph)) {
    names(res$quantities) <- vertex_attr(graph, "name", V(graph))
  }
  res
}

